import React, { useState, useEffect } from 'react';

export default function Navbar({ page, setPage }) {
  const [menuOpen, setMenuOpen] = useState(false);
  const [theme, setTheme] = useState('dark');

  useEffect(() => {
    document.documentElement.dataset.theme = theme;
  }, [theme]);

  const toggleTheme = () => setTheme(t => t === 'dark' ? 'light' : 'dark');
  const closeMenu = () => setMenuOpen(false);

  const links = [
    { key: 'home',      label: 'Home' },
    { key: 'info',      label: 'Info' },
    { key: 'rules',     label: 'Rules' },
    { key: 'players',   label: 'Players' },
    { key: 'standings', label: 'Standings' },
    { key: 'fixtures',  label: 'Fixture' },
  ];

  const handleNav = (key) => {
    setPage(key);
    closeMenu();
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  return (
    <>
      <nav style={navStyle}>
        <button onClick={() => handleNav('home')} style={logoStyle}>
          USF<span style={{ color: 'var(--text)' }}> | 2026</span>
        </button>

        <ul style={linksStyle}>
          {links.map(l => (
            <li key={l.key}>
              <button
                onClick={() => handleNav(l.key)}
                style={{
                  ...linkStyle,
                  color: page === l.key ? 'var(--accent)' : 'var(--text2)',
                  background: page === l.key ? 'rgba(230,57,70,0.1)' : 'transparent',
                }}
                onMouseEnter={e => { e.target.style.color = 'var(--accent)'; e.target.style.background = 'rgba(230,57,70,0.1)'; }}
                onMouseLeave={e => {
                  e.target.style.color = page === l.key ? 'var(--accent)' : 'var(--text2)';
                  e.target.style.background = page === l.key ? 'rgba(230,57,70,0.1)' : 'transparent';
                }}>
                {l.label}
              </button>
            </li>
          ))}
        </ul>

        <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
          <button style={themeToggleStyle} onClick={toggleTheme} title="Toggle theme">
            {theme === 'dark' ? '🌙' : '☀️'}
          </button>
          <button
            style={hamburgerBtnStyle}
            onClick={() => setMenuOpen(o => !o)}
            aria-label="Toggle menu"
          >
            <span style={{ ...hamLineStyle, transform: menuOpen ? 'rotate(45deg) translate(5px,5px)' : 'none' }} />
            <span style={{ ...hamLineStyle, opacity: menuOpen ? 0 : 1 }} />
            <span style={{ ...hamLineStyle, transform: menuOpen ? 'rotate(-45deg) translate(5px,-5px)' : 'none' }} />
          </button>
        </div>
      </nav>

      {menuOpen && (
        <div style={mobileNavStyle}>
          {links.map(l => (
            <button key={l.key} onClick={() => handleNav(l.key)}
              style={{
                ...mobileLinkStyle,
                color: page === l.key ? 'var(--accent)' : 'var(--text2)',
                background: page === l.key ? 'rgba(230,57,70,0.1)' : 'transparent',
              }}
              onMouseEnter={e => { e.target.style.color = 'var(--accent)'; e.target.style.background = 'rgba(230,57,70,0.1)'; }}
              onMouseLeave={e => {
                e.target.style.color = page === l.key ? 'var(--accent)' : 'var(--text2)';
                e.target.style.background = page === l.key ? 'rgba(230,57,70,0.1)' : 'transparent';
              }}>
              {l.label}
            </button>
          ))}
        </div>
      )}
    </>
  );
}

const navStyle = {
  position: 'fixed',
  top: 0, left: 0, right: 0,
  zIndex: 1000,
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  padding: '14px 24px',
  background: 'rgba(10,10,15,0.85)',
  backdropFilter: 'blur(20px)',
  borderBottom: '1px solid var(--border)',
};
const logoStyle = {
  fontFamily: "'Bebas Neue', sans-serif",
  fontSize: '1.6rem',
  letterSpacing: 3,
  color: 'var(--accent)',
  background: 'none',
  border: 'none',
  cursor: 'pointer',
  display: 'flex',
  alignItems: 'center',
  gap: 8,
  padding: 0,
};
const linksStyle = {
  display: 'flex',
  gap: 4,
  listStyle: 'none',
  alignItems: 'center',
  margin: 0,
  padding: 0,
  '@media(maxWidth:768px)': { display: 'none' },
};
const linkStyle = {
  background: 'none',
  border: 'none',
  cursor: 'pointer',
  color: 'var(--text2)',
  textDecoration: 'none',
  fontWeight: 600,
  fontSize: '0.85rem',
  letterSpacing: 1.5,
  textTransform: 'uppercase',
  padding: '6px 12px',
  borderRadius: 6,
  transition: 'all 0.2s',
  display: 'block',
  fontFamily: "'Rajdhani', sans-serif",
};
const themeToggleStyle = {
  background: 'var(--card)',
  border: '1px solid var(--border)',
  color: 'var(--text)',
  width: 36, height: 36,
  borderRadius: '50%',
  cursor: 'pointer',
  display: 'flex', alignItems: 'center', justifyContent: 'center',
  fontSize: '1rem',
};
const hamburgerBtnStyle = {
  display: 'flex',
  flexDirection: 'column',
  gap: 5,
  cursor: 'pointer',
  background: 'none',
  border: 'none',
  padding: 4,
};
const hamLineStyle = {
  display: 'block',
  width: 24, height: 2,
  background: 'var(--text)',
  borderRadius: 2,
  transition: 'all 0.3s',
};
const mobileNavStyle = {
  position: 'fixed',
  top: 65, left: 0, right: 0,
  background: 'var(--bg2)',
  borderBottom: '1px solid var(--border)',
  padding: 16,
  zIndex: 999,
  display: 'flex',
  flexDirection: 'column',
  gap: 4,
};
const mobileLinkStyle = {
  background: 'none',
  border: 'none',
  cursor: 'pointer',
  color: 'var(--text2)',
  fontWeight: 600,
  fontSize: '1rem',
  letterSpacing: 1,
  textTransform: 'uppercase',
  padding: '10px 16px',
  borderRadius: 8,
  transition: 'all 0.2s',
  textAlign: 'left',
  fontFamily: "'Rajdhani', sans-serif",
  width: '100%',
};
